     1→import {
     2→  Injectable,
     3→  UnauthorizedException,
     4→  BadRequestException,
     5→  ConflictException,
     6→  Inject,
     7→  forwardRef,
     8→  Logger,
     9→} from '@nestjs/common';
    10→import { JwtService, JwtSignOptions } from '@nestjs/jwt';
    11→import { ConfigType } from '@nestjs/config';
    12→import { jwtConfig } from '@configs/jwt.config';
    13→import { Db } from '@shared/database/types';
    14→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
    15→import { randomBytes, UUID } from 'crypto';
    16→import { SignInDto } from '../dto/signin.dto';
    17→import { AuthResponseDto, RefreshResponseDto } from '../dto/auth-response.dto';
    18→import { RefreshTokenDto } from '../dto/refresh-token.dto';
    19→import { RegisterDto } from '../dto/register.dto';
    20→import { RegisterWithInvitationDto } from '../dto/register-with-invitation.dto';
    21→import { SetPasswordDto } from '../dto/set-password.dto';
    22→import { VerifyEmailDto } from '../dto/verify-email.dto';
    23→import { JwtPayload } from '../strategies/jwt.strategy';
    24→import { PasswordService } from './password.service';
    25→import { TenantInvitationService } from './tenant-invitation.service';
    26→import { EmailVerificationService } from './email-verification.service';
    27→import { TenantService } from '@modules/tenant/services/tenant.service';
    28→import { TenantAccountService } from '@modules/balance/services/tenant-account.service';
    29→import { AuthProviderType } from '@entities/user-auth-provider.entity';
    30→import { UserService } from '@modules/users/services/user.service';
    31→import { ControlledTransaction } from 'kysely';
    32→import { Database } from 'src/db/database.type';
    33→
    34→@Injectable()
    35→export class AuthService {
    36→  private readonly logger = new Logger(AuthService.name);
    37→
    38→  constructor(
    39→    @Inject(DATABASE_CONNECTION_TOKEN)
    40→    private readonly db: Db,
    41→    private readonly jwtService: JwtService,
    42→    @Inject(jwtConfig.KEY)
    43→    private readonly config: ConfigType<typeof jwtConfig>,
    44→    private readonly passwordService: PasswordService,
    45→    private readonly tenantInvitationService: TenantInvitationService,
    46→    private readonly emailVerificationService: EmailVerificationService,
    47→    @Inject(forwardRef(() => TenantService))
    48→    private readonly tenantService: TenantService,
    49→    @Inject(forwardRef(() => TenantAccountService))
    50→    private readonly tenantAccountService: TenantAccountService,
    51→    private readonly userService: UserService,
    52→  ) {}
    53→
    54→  /**
    55→   * Validate a refresh token by its DB ID.
    56→   */
    57→  async validateRefreshToken(tokenId: UUID, executor?: Db) {
    58→    return (executor ?? this.db)
    59→      .selectFrom('refreshToken')
    60→      .innerJoin('user', 'refreshToken.userId', 'user.id')
    61→      .innerJoin('userAuthProvider', 'user.id', 'userAuthProvider.userId')
    62→      .select([
    63→        'refreshToken.id',
    64→        'refreshToken.token',
    65→        'refreshToken.userId',
    66→        'refreshToken.expiresAt',
    67→        'user.email',
    68→        'user.tenantId',
    69→        'user.role',
    70→        'user.isActive',
    71→        'user.emailVerified',
    72→        'userAuthProvider.providerUserId',
    73→      ])
    74→      .where('refreshToken.id', '=', tokenId)
    75→      .where('refreshToken.expiresAt', '>', new Date())
    76→      .where('user.isActive', '=', true)
    77→      .executeTakeFirst();
    78→  }
