    80→  async signIn(signInDto: SignInDto): Promise<AuthResponseDto> {
    81→    const trx = await this.db.startTransaction().execute();
    82→
    83→    try {
    84→      const user = await this.userService.findUser(
    85→        { email: signInDto.email, isActive: true },
    86→        trx,
    87→      );
    88→
    89→      if (!user) {
    90→        throw new UnauthorizedException('Invalid credentials');
    91→      }
    92→
    93→      // Check if user has a local auth provider
    94→      const localAuthProvider = await trx
    95→        .selectFrom('userAuthProvider')
    96→        .selectAll()
    97→        .where('userId', '=', user.id)
    98→        .where('provider', '=', 'local')
    99→        .executeTakeFirst();
   100→
   101→      if (!localAuthProvider) {
   102→        throw new UnauthorizedException(
   103→          'No password set. Please use OAuth or set a password.',
   104→        );
   105→      }
   106→
   107→      const isPasswordValid = await this.passwordService.comparePassword(
   108→        signInDto.password,
   109→        user.password,
   110→      );
   111→
   112→      if (!isPasswordValid) {
   113→        throw new UnauthorizedException('Invalid credentials');
   114→      }
   115→
   116→      return this.generateTokens(
   117→        user.id,
   118→        user.email,
   119→        user.role as 'ADMIN' | 'USER',
   120→        user.tenantId,
   121→        user.emailVerified,
   122→        trx,
   123→      );
   124→    } catch (error) {
   125→      await trx.rollback().execute();
   126→      if (error instanceof UnauthorizedException) {
   127→        throw error;
   128→      }
   129→      throw new UnauthorizedException('Invalid credentials');
   130→    }
   131→  }
