   133→  async register(registerDto: RegisterDto): Promise<AuthResponseDto> {
   134→    const trx = await this.db.startTransaction().execute();
   135→
   136→    try {
   137→      const existingUser = await this.userService.findUser(
   138→        { email: registerDto.email },
   139→        trx,
   140→      );
   141→
   142→      if (existingUser) {
   143→        throw new ConflictException('User with this email already exists');
   144→      }
   145→
   146→      // Hash password
   147→      const hashedPassword = await this.passwordService.hashPassword(
   148→        registerDto.password,
   149→      );
   150→
   151→      // Create user without tenant — frontend will redirect to tenant creation
   152→      const user = await trx
   153→        .insertInto('user')
   154→        .values({
   155→          email: registerDto.email,
   156→          password: hashedPassword,
   157→          role: 'USER',
   158→          isActive: true,
   159→          emailVerified: false,
   160→          tenantId: null,
   161→        })
   162→        .returningAll()
   163→        .executeTakeFirstOrThrow();
   164→
   165→      await trx
   166→        .insertInto('userAuthProvider')
   167→        .values({
   168→          userId: user.id,
   169→          provider: 'local',
   170→          providerUserId: null,
   171→        })
   172→        .execute();
   173→
   174→      await this.emailVerificationService.sendVerificationCode(
   175→        user.id,
   176→        user.email,
   177→        trx,
   178→      );
   179→
   180→      await trx.commit().execute();
   181→
   182→      return this.generateTokens(
   183→        user.id,
   184→        user.email,
   185→        user.role as 'ADMIN' | 'USER',
   186→        user.tenantId,
   187→        user.emailVerified,
   188→        null,
   189→      );
   190→    } catch (error) {
   191→      await trx.rollback().execute();
   192→      if (
   193→        error instanceof ConflictException ||
   194→        error instanceof BadRequestException
   195→      ) {
   196→        throw error;
   197→      }
   198→      throw new BadRequestException('Registration failed');
   199→    }
   200→  }
