   202→  async registerWithInvitation(
   203→    registerDto: RegisterWithInvitationDto,
   204→  ): Promise<AuthResponseDto> {
   205→    const trx = await this.db.startTransaction().execute();
   206→
   207→    try {
   208→      const invitation = await this.tenantInvitationService.validateInvitation(
   209→        registerDto.invitationToken,
   210→        trx,
   211→      );
   212→
   213→      const existingUser = await this.userService.findUser(
   214→        { email: registerDto.email },
   215→        trx,
   216→      );
   217→
   218→      if (existingUser) {
   219→        // User exists, link to tenant if not already linked
   220→        if (existingUser.tenantId !== invitation.tenantId) {
   221→          throw new ConflictException(
   222→            'User already exists with a different tenant',
   223→          );
   224→        }
   225→        await this.tenantInvitationService.markInvitationAsUsed(
   226→          registerDto.invitationToken,
   227→          trx,
   228→        );
   229→        return this.generateTokens(
   230→          existingUser.id,
   231→          existingUser.email,
   232→          existingUser.role as 'ADMIN' | 'USER',
   233→          existingUser.tenantId,
   234→          existingUser.emailVerified,
   235→          null,
   236→        );
   237→      }
   238→
   239→      // Verify email matches invitation
   240→      if (registerDto.email.toLowerCase() !== invitation.email.toLowerCase()) {
   241→        throw new BadRequestException('Email does not match invitation');
   242→      }
   243→
   244→      // Hash password if provided (for local registration)
   245→      let hashedPassword: string | null = null;
   246→      if (registerDto.password) {
   247→        hashedPassword = await this.passwordService.hashPassword(
   248→          registerDto.password,
   249→        );
   250→      }
   251→
   252→      const user = await trx
   253→        .insertInto('user')
   254→        .values({
   255→          email: registerDto.email,
   256→          password: hashedPassword,
   257→          role: 'USER',
   258→          isActive: true,
   259→          emailVerified: true,
   260→          tenantId: invitation.tenantId,
   261→        })
   262→        .returningAll()
   263→        .executeTakeFirstOrThrow();
   264→
   265→      // Create auth provider (local if password provided, otherwise will be created by OAuth)
   266→      if (registerDto.password) {
   267→        await trx
   268→          .insertInto('userAuthProvider')
   269→          .values({
   270→            userId: user.id,
   271→            provider: 'local',
   272→            providerUserId: null,
   273→          })
   274→          .execute();
   275→      }
   276→
   277→      await this.tenantInvitationService.markInvitationAsUsed(
   278→        registerDto.invitationToken,
   279→        trx,
   280→      );
   281→
   282→      await trx.commit().execute();
   283→
   284→      return this.generateTokens(
   285→        user.id,
   286→        user.email,
   287→        user.role as 'ADMIN' | 'USER',
   288→        user.tenantId,
   289→        user.emailVerified,
   290→        null,
   291→      );
   292→    } catch (error) {
   293→      await trx.rollback().execute();
   294→      if (
   295→        error instanceof ConflictException ||
   296→        error instanceof BadRequestException
   297→      ) {
   298→        throw error;
   299→      }
   300→      throw new BadRequestException('Registration failed');
   301→    }
   302→  }
