   304→  async handleOAuthCallback(
   305→    provider: AuthProviderType,
   306→    providerUserId: string,
   307→    email: string,
   308→    invitationToken?: string,
   309→  ): Promise<AuthResponseDto> {
   310→    const trx = await this.db.startTransaction().execute();
   311→
   312→    try {
   313→      let user = await this.userService.findUser({ email }, trx);
   314→
   315→      let tenantId: number | null = null;
   316→
   317→      // Handle invitation if provided
   318→      if (invitationToken) {
   319→        const invitation =
   320→          await this.tenantInvitationService.validateInvitation(
   321→            invitationToken,
   322→            trx,
   323→          );
   324→        tenantId = invitation.tenantId;
   325→
   326→        // Verify email matches invitation
   327→        if (email.toLowerCase() !== invitation.email.toLowerCase()) {
   328→          throw new BadRequestException('Email does not match invitation');
   329→        }
   330→      }
   331→
   332→      if (user) {
   333→        // User exists, link OAuth provider if not already linked
   334→        const existingProvider = await trx
   335→          .selectFrom('userAuthProvider')
   336→          .selectAll()
   337→          .where('userId', '=', user.id)
   338→          .where('provider', '=', provider)
   339→          .executeTakeFirst();
   340→
   341→        if (!existingProvider) {
   342→          await trx
   343→            .insertInto('userAuthProvider')
   344→            .values({
   345→              userId: user.id,
   346→              provider: provider,
   347→              providerUserId: providerUserId,
   348→            })
   349→            .execute();
   350→        }
   351→
   352→        // Update tenant if invitation provided and user has no tenant
   353→        if (invitationToken && tenantId && user.tenantId !== tenantId) {
   354→          await trx
   355→            .updateTable('user')
   356→            .set({ tenantId: tenantId })
   357→            .where('id', '=', user.id)
   358→            .execute();
   359→          const updated = await this.userService.findUser({ id: user.id }, trx);
   360→          if (!updated) throw new BadRequestException('User not found');
   361→          user = updated;
   362→        }
   363→
   364→        if (invitationToken) {
   365→          await this.tenantInvitationService.markInvitationAsUsed(
   366→            invitationToken,
   367→            trx,
   368→          );
   369→        }
   370→
   371→        await trx.commit().execute();
   372→        return this.generateTokens(
   373→          user.id,
   374→          user.email,
   375→          user.role as 'ADMIN' | 'USER',
   376→          user.tenantId,
   377→          user.emailVerified,
   378→          null,
   379→        );
   380→      } else {
   381→        // New user via OAuth
   382→        const newTenantId = tenantId ?? null; // null = no tenant yet
   383→
   384→        user = await trx
   385→          .insertInto('user')
   386→          .values({
   387→            email: email,
   388→            password: null,
   389→            role: 'USER',
   390→            isActive: true,
   391→            emailVerified: true,
   392→            tenantId: newTenantId,
   393→          })
   394→          .returningAll()
   395→          .executeTakeFirstOrThrow();
   396→
   397→        // Create OAuth auth provider
   398→        await trx
   399→          .insertInto('userAuthProvider')
   400→          .values({
   401→            userId: user.id,
   402→            provider: provider,
   403→            providerUserId: providerUserId,
   404→          })
   405→          .execute();
   406→
   407→        if (invitationToken) {
   408→          await this.tenantInvitationService.markInvitationAsUsed(
   409→            invitationToken,
   410→            trx,
   411→          );
   412→        }
   413→
   414→        await trx.commit().execute();
   415→        return this.generateTokens(
   416→          user.id,
   417→          user.email,
   418→          user.role as 'ADMIN' | 'USER',
   419→          user.tenantId,
   420→          user.emailVerified,
   421→          null,
   422→        );
   423→      }
   424→    } catch (error) {
   425→      await trx.rollback().execute();
   426→      if (
   427→        error instanceof ConflictException ||
   428→        error instanceof BadRequestException
   429→      ) {
   430→        throw error;
   431→      }
   432→      throw new BadRequestException('OAuth authentication failed');
   433→    }
   434→  }
