   436→  async setPassword(
   437→    userId: UUID,
   438→    setPasswordDto: SetPasswordDto,
   439→  ): Promise<void> {
   440→    const trx = await this.db.startTransaction().execute();
   441→
   442→    try {
   443→      // Hash password
   444→      const hashedPassword = await this.passwordService.hashPassword(
   445→        setPasswordDto.password,
   446→      );
   447→
   448→      // Update user password
   449→      await trx
   450→        .updateTable('user')
   451→        .set({ password: hashedPassword })
   452→        .where('id', '=', userId)
   453→        .execute();
   454→
   455→      // Create local auth provider if it doesn't exist
   456→      const existingProvider = await trx
   457→        .selectFrom('userAuthProvider')
   458→        .selectAll()
   459→        .where('userId', '=', userId)
   460→        .where('provider', '=', 'local')
   461→        .executeTakeFirst();
   462→
   463→      if (!existingProvider) {
   464→        await trx
   465→          .insertInto('userAuthProvider')
   466→          .values({
   467→            userId: userId,
   468→            provider: 'local',
   469→            providerUserId: null,
   470→          })
   471→          .execute();
   472→      }
   473→
   474→      await trx.commit().execute();
   475→    } catch {
   476→      await trx.rollback().execute();
   477→      throw new BadRequestException('Failed to set password');
   478→    }
   479→  }
