   481→  async refresh(refreshTokenDto: RefreshTokenDto): Promise<RefreshResponseDto> {
   482→    const decoded = this.jwtService.verify(refreshTokenDto.refreshToken, {
   483→      secret: this.config.refreshTokenSecret,
   484→    }) as { sub: string; tokenId: string };
   485→
   486→    const refreshToken = await this.validateRefreshToken(
   487→      decoded.tokenId as UUID,
   488→    );
   489→    if (!refreshToken) {
   490→      throw new UnauthorizedException('Invalid or expired refresh token');
   491→    }
   492→
   493→    const accessTokenPayload: JwtPayload = {
   494→      sub: refreshToken.userId as string,
   495→      email: refreshToken.email,
   496→      providerUserId: refreshToken.providerUserId,
   497→      tenantId: refreshToken.tenantId,
   498→    };
   499→
   500→    const accessToken = this.jwtService.sign(accessTokenPayload, {
   501→      secret: this.config.accessTokenSecret,
   502→      expiresIn: this.config.accessTokenExpiresIn,
   503→    } as JwtSignOptions);
   504→
   505→    return {
   506→      accessToken,
   507→      user: {
   508→        id: refreshToken.userId as string,
   509→        email: refreshToken.email,
   510→        role: refreshToken.role as 'ADMIN' | 'USER',
   511→        tenantId: refreshToken.tenantId,
   512→        emailVerified: refreshToken.emailVerified,
   513→      },
   514→    };
   515→  }
