   517→  async verifyEmail(
   518→    userId: UUID,
   519→    verifyEmailDto: VerifyEmailDto,
   520→  ): Promise<AuthResponseDto> {
   521→    const verified = await this.emailVerificationService.verifyCode(
   522→      userId,
   523→      verifyEmailDto.code,
   524→    );
   525→
   526→    if (!verified) {
   527→      throw new BadRequestException('Invalid or expired verification code');
   528→    }
   529→
   530→    const user = await this.userService.findUser({ id: userId });
   531→    if (!user) {
   532→      throw new BadRequestException('User not found');
   533→    }
   534→
   535→    return this.generateTokens(
   536→      user.id,
   537→      user.email,
   538→      user.role as 'ADMIN' | 'USER',
   539→      user.tenantId,
   540→      true,
   541→      null,
   542→    );
   543→  }
   544→
   545→  async resendVerificationCode(userId: UUID, email: string): Promise<void> {
   546→    await this.emailVerificationService.sendVerificationCode(userId, email);
   547→  }
   548→
   549→  async logout(userId: UUID): Promise<void> {
   550→    // Delete all refresh tokens for this user
   551→    await this.db
   552→      .deleteFrom('refreshToken')
   553→      .where('userId', '=', userId)
   554→      .execute();
   555→  }
