   557→  /**
   558→   * Generate access and refresh tokens for a user.
   559→   * Always commits the transaction (creates its own if none passed).
   560→   */
   561→  private async generateTokens(
   562→    userId: UUID,
   563→    email: string,
   564→    role: 'ADMIN' | 'USER',
   565→    tenantId: number | null,
   566→    emailVerified: boolean,
   567→    trx?: ControlledTransaction<Database, []>,
   568→  ): Promise<AuthResponseDto> {
   569→    const ownTrx = !trx;
   570→    if (ownTrx) {
   571→      trx = await this.db.startTransaction().execute();
   572→    }
   573→
   574→    try {
   575→      // Generate refresh token
   576→      const refreshTokenValue = randomBytes(64).toString('hex');
   577→      const expiresAt = new Date();
   578→      expiresAt.setTime(
   579→        expiresAt.getTime() +
   580→          this.parseExpiration(this.config.refreshTokenExpiresIn) * 1000,
   581→      );
   582→
   583→      const providerUserId = await trx
   584→        .selectFrom('userAuthProvider')
   585→        .select('providerUserId')
   586→        .where('userId', '=', userId)
   587→        .executeTakeFirst();
   588→
   589→      // Store refresh token in database
   590→      const refreshToken = await trx
   591→        .insertInto('refreshToken')
   592→        .values({
   593→          token: refreshTokenValue,
   594→          userId: userId,
   595→          expiresAt: expiresAt,
   596→        })
   597→        .returningAll()
   598→        .executeTakeFirstOrThrow();
   599→
   600→      // Generate access token
   601→      const accessTokenPayload: JwtPayload = {
   602→        sub: userId as string,
   603→        email: email,
   604→        providerUserId: providerUserId?.providerUserId,
   605→        tenantId: tenantId,
   606→      };
   607→
   608→      const accessToken = this.jwtService.sign(accessTokenPayload, {
   609→        secret: this.config.accessTokenSecret,
   610→        expiresIn: this.config.accessTokenExpiresIn,
   611→      } as JwtSignOptions);
   612→
   613→      // Generate refresh token JWT (contains the DB token ID for validation)
   614→      const refreshTokenPayload = {
   615→        sub: userId as string,
   616→        tokenId: refreshToken.id as string,
   617→      };
   618→
   619→      const refreshTokenJwt = this.jwtService.sign(refreshTokenPayload, {
   620→        secret: this.config.refreshTokenSecret,
   621→        expiresIn: this.config.refreshTokenExpiresIn,
   622→      } as JwtSignOptions);
   623→
   624→      // Always commit — generateTokens is the final step of every auth flow
   625→      await trx.commit().execute();
   626→
   627→      return {
   628→        accessToken,
   629→        refreshToken: refreshTokenJwt,
   630→        user: {
   631→          id: userId as string,
   632→          email,
   633→          role,
   634→          tenantId,
   635→          emailVerified,
   636→        },
   637→      };
   638→    } catch (error) {
   639→      await trx.rollback().execute();
   640→      throw error;
   641→    }
   642→  }
   643→
   644→  private parseExpiration(expiresIn: string): number {
   645→    // Parse expiration string like "7d", "15m", "1h" to seconds
   646→    const match = expiresIn.match(/^(\d+)([smhd])$/);
   647→    if (!match) {
   648→      return 7 * 24 * 60 * 60; // Default to 7 days in seconds
   649→    }
   650→
   651→    const value = parseInt(match[1], 10);
   652→    const unit = match[2];
   653→
   654→    switch (unit) {
   655→      case 's':
   656→        return value;
   657→      case 'm':
   658→        return value * 60;
   659→      case 'h':
   660→        return value * 60 * 60;
   661→      case 'd':
   662→        return value * 24 * 60 * 60;
   663→      default:
   664→        return 7 * 24 * 60 * 60;
   665→    }
   666→  }
   667→}
