     1→import { Injectable, Inject, Logger } from '@nestjs/common';
     2→import { Db } from '@shared/database/types';
     3→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
     4→import { UUID } from 'crypto';
     5→import { EmailService } from '@modules/email/services/email.service';
     6→
     7→@Injectable()
     8→export class EmailVerificationService {
     9→  private readonly logger = new Logger(EmailVerificationService.name);
    10→
    11→  constructor(
    12→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    13→    private readonly emailService: EmailService,
    14→  ) {}
    15→
    16→  async sendVerificationCode(
    17→    userId: UUID,
    18→    email: string,
    19→    executor?: Db,
    20→  ): Promise<void> {
    21→    const code = Math.floor(100000 + Math.random() * 900000).toString();
    22→
    23→    const expiresAt = new Date();
    24→    expiresAt.setMinutes(expiresAt.getMinutes() + 15);
    25→
    26→    await (executor ?? this.db)
    27→      .insertInto('emailVerificationCode')
    28→      .values({
    29→        userId,
    30→        code,
    31→        expiresAt,
    32→      })
    33→      .execute();
    34→
    35→    this.emailService.sendVerificationCodeEmail(email, code).catch((err) => {
    36→      this.logger.error(
    37→        `Failed to send verification code email to ${email}: ${err?.message}`,
    38→        err?.stack,
    39→      );
    40→    });
    41→  }
    42→
    43→  async verifyCode(
    44→    userId: UUID,
    45→    code: string,
    46→    executor?: Db,
    47→  ): Promise<boolean> {
    48→    const db = executor ?? this.db;
    49→
    50→    const record = await db
    51→      .selectFrom('emailVerificationCode')
    52→      .selectAll()
    53→      .where('userId', '=', userId)
    54→      .where('code', '=', code)
    55→      .where('usedAt', 'is', null)
    56→      .where('expiresAt', '>', new Date())
    57→      .executeTakeFirst();
    58→
    59→    if (!record) {
    60→      return false;
    61→    }
    62→
    63→    await db
    64→      .updateTable('emailVerificationCode')
    65→      .set({ usedAt: new Date() })
    66→      .where('id', '=', record.id)
    67→      .execute();
    68→
    69→    await db
    70→      .updateTable('user')
    71→      .set({ emailVerified: true })
    72→      .where('id', '=', userId)
    73→      .execute();
    74→
    75→    return true;
    76→  }
    77→
    78→  async isEmailVerified(userId: UUID, executor?: Db): Promise<boolean> {
    79→    const user = await (executor ?? this.db)
    80→      .selectFrom('user')
    81→      .select('emailVerified')
    82→      .where('id', '=', userId)
    83→      .executeTakeFirst();
    84→
    85→    return user?.emailVerified ?? false;
    86→  }
    87→}
