     1→import {
     2→  Injectable,
     3→  BadRequestException,
     4→  NotFoundException,
     5→  Logger,
     6→} from '@nestjs/common';
     7→import { Db } from '@shared/database/types';
     8→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
     9→import { Inject } from '@nestjs/common';
    10→import { UUID } from 'crypto';
    11→import { randomBytes } from 'crypto';
    12→import { Selectable } from 'kysely';
    13→import { TenantInvitationEntity } from '@entities/tenant-invitation.entity';
    14→import { EmailService } from '@modules/email/services/email.service';
    15→
    16→@Injectable()
    17→export class TenantInvitationService {
    18→  private readonly logger = new Logger(TenantInvitationService.name);
    19→
    20→  constructor(
    21→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    22→    private readonly emailService: EmailService,
    23→  ) {}
    24→
    25→  /**
    26→   * Create a tenant invitation and send the invitation email
    27→   * @param tenantId Tenant ID
    28→   * @param email Email to invite
    29→   * @param invitedByUserId User ID who created the invitation
    30→   * @param expiresInDays Number of days until expiration (default: 7)
    31→   * @returns Created invitation (without token)
    32→   */
    33→  async createInvitation(
    34→    tenantId: number,
    35→    email: string,
    36→    invitedByUserId: UUID,
    37→    expiresInDays: number = 7,
    38→  ): Promise<Omit<Selectable<TenantInvitationEntity>, 'token'>> {
    39→    const trx = await this.db.startTransaction().execute();
    40→
    41→    try {
    42→      // Check if there's already an unused invitation for this email and tenant
    43→      const existingInvitation = await trx
    44→        .selectFrom('tenantInvitation')
    45→        .selectAll()
    46→        .where('tenantId', '=', tenantId)
    47→        .where('email', '=', email)
    48→        .where('usedAt', 'is', null)
    49→        .where('expiresAt', '>', new Date())
    50→        .executeTakeFirst();
    51→
    52→      if (existingInvitation) {
    53→        throw new BadRequestException(
    54→          'An active invitation already exists for this email',
    55→        );
    56→      }
    57→
    58→      // Generate secure token
    59→      const token = this.generateSecureToken();
    60→
    61→      // Calculate expiration date
    62→      const expiresAt = new Date();
    63→      expiresAt.setDate(expiresAt.getDate() + expiresInDays);
    64→
    65→      // Create invitation
    66→      const invitation = await trx
    67→        .insertInto('tenantInvitation')
    68→        .values({
    69→          tenantId,
    70→          email,
    71→          token,
    72→          invitedByUserId,
    73→          expiresAt,
    74→        })
    75→        .returningAll()
    76→        .executeTakeFirstOrThrow();
    77→
    78→      // Fetch tenant name and inviter email for the invitation email
    79→      const tenant = await trx
    80→        .selectFrom('tenant')
    81→        .select(['name'])
    82→        .where('id', '=', tenantId)
    83→        .executeTakeFirst();
    84→
    85→      const inviter = await trx
    86→        .selectFrom('user')
    87→        .select(['email'])
    88→        .where('id', '=', invitedByUserId)
    89→        .executeTakeFirst();
    90→
    91→      await trx.commit().execute();
    92→
    93→      // Send invitation email (fire-and-forget, don't fail the request)
    94→      this.emailService
    95→        .sendInvitationEmail(
    96→          email,
    97→          token,
    98→          tenant?.name ?? 'Unknown',
    99→          inviter?.email ?? 'A team member',
   100→        )
   101→        .catch((err) => {
   102→          this.logger.error(
   103→            `Failed to send invitation email to ${email}: ${err.message}`,
   104→            err.stack,
   105→          );
   106→        });
   107→
   108→      // Return invitation without the sensitive token
   109→      const { token: _token, ...safeInvitation } = invitation;
   110→      return safeInvitation;
   111→    } catch (error) {
   112→      await trx.rollback().execute();
   113→      throw error;
   114→    }
   115→  }
   116→
   117→  /**
   118→   * Validate an invitation token
   119→   * @param token Invitation token
   120→   * @returns Invitation if valid
   121→   * @throws NotFoundException if invitation not found or invalid
   122→   */
   123→  async validateInvitation(
   124→    token: string,
   125→    executor?: Db,
   126→  ): Promise<Selectable<TenantInvitationEntity>> {
   127→    const invitation = await (executor ?? this.db)
   128→      .selectFrom('tenantInvitation')
   129→      .selectAll()
   130→      .where('token', '=', token)
   131→      .executeTakeFirst();
   132→
   133→    if (!invitation) {
   134→      throw new NotFoundException('Invitation not found');
   135→    }
   136→
   137→    if (invitation.usedAt) {
   138→      throw new BadRequestException('Invitation has already been used');
   139→    }
   140→
   141→    if (new Date(invitation.expiresAt) < new Date()) {
   142→      throw new BadRequestException('Invitation has expired');
   143→    }
   144→
   145→    return invitation;
   146→  }
   147→
   148→  /**
   149→   * Mark an invitation as used
   150→   * @param token Invitation token
   151→   */
   152→  async markInvitationAsUsed(token: string, executor?: Db): Promise<void> {
   153→    await (executor ?? this.db)
   154→      .updateTable('tenantInvitation')
   155→      .set({ usedAt: new Date() })
   156→      .where('token', '=', token)
   157→      .where('usedAt', 'is', null)
   158→      .execute();
   159→  }
   160→
   161→  /**
   162→   * Get invitations for a tenant
   163→   * @param tenantId Tenant ID
   164→   * @returns List of invitations
   165→   */
   166→  async getInvitationsByTenant(
   167→    tenantId: number,
   168→  ): Promise<Selectable<TenantInvitationEntity>[]> {
   169→    return this.db
   170→      .selectFrom('tenantInvitation')
   171→      .selectAll()
   172→      .where('tenantId', '=', tenantId)
   173→      .orderBy('createdAt', 'desc')
   174→      .execute();
   175→  }
   176→
   177→  /**
   178→   * Generate a cryptographically secure token
   179→   * @returns Secure token string
   180→   */
   181→  private generateSecureToken(): string {
   182→    return randomBytes(32).toString('hex');
   183→  }
   184→}
   185→

