     4→import { ConfigType } from '@nestjs/config';
     5→import { oauthConfig } from '@configs/oauth.config';
     6→
     7→export interface GoogleProfile {
     8→  id: string;
     9→  emails: { value: string; verified: boolean }[];
    10→  displayName: string;
    11→}
    12→
    13→@Injectable()
    14→export class GoogleStrategy extends PassportStrategy(Strategy, 'google') {
    15→  constructor(config: ConfigType<typeof oauthConfig>) {
    16→    super({
    17→      clientID: config.google.clientId,
    18→      clientSecret: config.google.clientSecret,
    19→      callbackURL: config.google.callbackURL,
    20→      scope: ['email', 'profile'],
    21→    });
    22→  }
    23→
    24→  async validate(
    25→    accessToken: string,
    26→    refreshToken: string,
    27→    profile: GoogleProfile,
    28→    done: VerifyCallback,
    29→  ): Promise<void> {
    30→    const email = profile.emails?.[0]?.value;
    31→    if (!email) {
    32→      done(new Error('No email found in Google profile'), undefined);
    33→      return;
    34→    }
    35→
    36→    const user = {
    37→      providerUserId: profile.id,
    38→      email,
    39→      displayName: profile.displayName,
    40→      provider: 'google' as const,
    41→    };
    42→
    43→    done(null, user);
    44→  }
    45→}
