     1→import { Injectable, UnauthorizedException } from '@nestjs/common';
     2→import { PassportStrategy } from '@nestjs/passport';
     3→import { ExtractJwt, Strategy } from 'passport-jwt';
     4→import { ConfigType } from '@nestjs/config';
     5→import { jwtConfig } from '@configs/jwt.config';
     6→import { Inject } from '@nestjs/common';
     7→import { UserService } from '@modules/users/services/user.service';
     8→import { RequestUser } from '@shared/types/request-user.interface';
     9→import { UUID } from 'crypto';
    10→
    11→export interface JwtPayload {
    12→  sub: string; // user id
    13→  email: string;
    14→  providerUserId?: string;
    15→  tenantId: number | null;
    16→}
    17→
    18→@Injectable()
    19→export class JwtStrategy extends PassportStrategy(Strategy, 'jwt') {
    20→  constructor(
    21→    @Inject(jwtConfig.KEY)
    22→    private readonly config: ConfigType<typeof jwtConfig>,
    23→    private readonly userService: UserService,
    24→  ) {
    25→    super({
    26→      jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
    27→      ignoreExpiration: false,
    28→      secretOrKey: config.accessTokenSecret,
    29→    });
    30→  }
    31→
    32→  async validate(payload: JwtPayload): Promise<RequestUser> {
    33→    const user = await this.userService.findUser({
    34→      id: payload.sub as UUID,
    35→      isActive: true,
    36→    });
    37→
    38→    if (!user) {
    39→      throw new UnauthorizedException('User not found or inactive');
    40→    }
    41→
    42→    return {
    43→      id: user.id,
    44→      email: user.email,
    45→      providerUserId: payload.providerUserId,
    46→      tenantId: user.tenantId,
    47→      role: user.role,
    48→      emailVerified: user.emailVerified,
    49→    };
    50→  }
    51→}
    52→

