     8→export interface SendEmailOptions {
     9→  to: string;
    10→  subject: string;
    11→  html?: string;
    12→  text?: string;
    13→}
    14→
    15→@Injectable()
    16→export class EmailService {
    17→  private readonly logger = new Logger(EmailService.name);
    18→  private transporter: Transporter | null = null;
    19→
    20→  constructor(
    21→    @Inject(emailConfig.KEY)
    22→    private readonly config: ConfigType<typeof emailConfig>,
    23→    @Inject(appConfig.KEY)
    24→    private readonly appConf: ConfigType<typeof appConfig>,
    25→  ) {
    26→    if (this.config.enabled) {
    27→      this.transporter = nodemailer.createTransport({
    28→        host: this.config.host,
    29→        port: this.config.port,
    30→        secure: this.config.secure,
    31→        auth: {
    32→          user: this.config.auth.user,
    33→          pass: this.config.auth.pass,
    34→        },
    35→      });
    36→      this.logger.log('Email service initialized');
    37→    } else {
    38→      this.logger.warn('Email service is disabled (EMAIL_ENABLED=false)');
    39→    }
    40→  }
    41→
    42→  async sendEmail(options: SendEmailOptions): Promise<void> {
    43→    if (!this.transporter) {
    44→      this.logger.warn(
    45→        `Email not sent (disabled). To: ${options.to}, Subject: ${options.subject}`,
    46→      );
    47→      return;
    48→    }
    49→
    50→    try {
    51→      await this.transporter.sendMail({
    52→        from: this.config.from,
    53→        to: options.to,
    54→        subject: options.subject,
    55→        html: options.html,
    56→        text: options.text,
    57→      });
    58→      this.logger.log(`Email sent to ${options.to}: ${options.subject}`);
    59→    } catch (error: unknown) {
    60→      this.logger.error(
    61→        `Failed to send email to ${options.to}: ${error instanceof Error ? error.message : 'Unknown error'}`,
    62→        error instanceof Error ? error.stack : undefined,
    63→      );
    64→      throw error;
    65→    }
    66→  }
    67→
