    71→      subject: 'Your verification code',
    72→      html: `
    73→        <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
    74→          <h2>Email Verification</h2>
    75→          <p>Your verification code is:</p>
