     8→export interface UserFilters {
     9→  id?: UUID;
    10→  email?: string;
    11→  isActive?: boolean;
    12→}
    13→
    14→@Injectable()
    15→export class UserService {
    16→  constructor(@Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db) {}
    17→
    18→  async findUser(
    19→    filters: UserFilters,
    20→    executor?: Db,
    21→  ): Promise<Selectable<UserEntity> | undefined> {
    22→    let query = (executor ?? this.db).selectFrom('user').selectAll();
    23→
    24→    if (filters.id !== undefined) {
    25→      query = query.where('id', '=', filters.id);
    26→    }
    27→    if (filters.email !== undefined) {
    28→      query = query.where('email', '=', filters.email);
    29→    }
    30→    if (filters.isActive !== undefined) {
    31→      query = query.where('isActive', '=', filters.isActive);
    32→    }
    33→
    34→    return query.executeTakeFirst();
    35→  }
    36→
    37→  async getUsers(tenantId: number): Promise<Selectable<UserEntity>[]> {
    38→    return this.db
    39→      .selectFrom('user')
    40→      .selectAll()
    41→      .where('tenantId', '=', tenantId)
    42→      .execute();
    43→  }
    44→}
